import React from "react";
import { useCart } from "../context/CartContext";
import { useNavigate } from "react-router-dom";
import "../styles/Cart.css";

const Cart = () => {
  const { cartItems, updateQuantity, removeFromCart, getTotal } = useCart();
  const navigate = useNavigate();

  const handleCheckout = () => {
    navigate("/checkout"); // or your checkout page
  };

  return (
    <div className="cart-page">
      <div className="cart-left">
        <h2>Shopping Cart <span>{cartItems.length} items</span></h2>
        {cartItems.map((item) => (
          <div className="cart-item" key={item.id}>
            <img src={item.image} alt={item.name} />
            <div className="cart-info">
              <p className="category">{item.category || "Product"}</p>
              <p className="name">{item.name}</p>
              <div className="quantity">
                <button onClick={() => updateQuantity(item.id, item.quantity - 1)}>-</button>
                <span>{item.quantity}</span>
                <button onClick={() => updateQuantity(item.id, item.quantity + 1)}>+</button>
              </div>
            </div>
            <div className="cart-price">
              ₹{item.price * item.quantity}
            </div>
            <button className="remove" onClick={() => removeFromCart(item.id)}>×</button>
          </div>
        ))}
      </div>

      <div className="cart-right">
        <h3>Summary</h3>
        <div className="summary-row">
          <span>Items {cartItems.length}</span>
          <span>₹{getTotal()}</span>
        </div>
        <div className="summary-row">
          <span>Shipping</span>
          <select>
            <option>Standard Delivery - ₹50</option>
            <option>Express Delivery - ₹100</option>
          </select>
        </div>
        <div className="summary-row">
          <span>Discount Code</span>
          <input type="text" placeholder="Enter your code" />
        </div>
        <div className="summary-total">
          <span>Total Price</span>
          <span>₹{getTotal() + 50}</span> {/* Example with standard shipping */}
        </div>
        <button className="checkout-btn" onClick={handleCheckout}>
          CHECKOUT
        </button>
      </div>
    </div>
  );
};

export default Cart;
